import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as o,e as n}from"./app-86031e78.js";const r={},i=n('<h1 id="introduce-to-cloud" tabindex="-1"><a class="header-anchor" href="#introduce-to-cloud" aria-hidden="true">#</a> Introduce to Cloud</h1><h2 id="what-is-the-cloud" tabindex="-1"><a class="header-anchor" href="#what-is-the-cloud" aria-hidden="true">#</a> What is the Cloud</h2><p>A computing paradigm where <strong>data</strong> and <strong>services</strong> reside in <u>massively scalable data centers</u> and can be ubiquitously accessed from any connected devices <u>over the Internet</u>.</p><p>「一种计算模式，数据和服务驻留在大规模可扩展的数据中心，并可通过互联网从任何连接设备进行普遍访问。」</p><p>狭窄/简短的说法：</p><ul><li>Utility Computing「效用计算」 的升级版：基本上是通过互联网提供虚拟服务器。</li><li>效用计算：一种服务提供模式；服务提供商根据需要向客户提供计算资源和基础设施管理，并按特定使用情况而不是统一费率收费。</li></ul><p>More Practical 的说法：</p><ul><li>云计算 是 &quot;指<u>利用大规模数据中心</u>通过<strong>互联网</strong>提供的软件、存储或处理服务&quot;。</li><li>Cloud computing, the notion of &quot;outsourcing hardware and software to Internet service providers「将硬件和软件外包给互联网服务提供商」&quot;,.......<strong>(Key:&quot;Don&#39;t do it yourself !&quot;</strong></li></ul><img src="https://pic.hanjiaming.com.cn/2024/02/16/5a7cd4b117d2f.png" alt="1708068869283.png" style="zoom:33%;">',9),a=[i];function c(s,d){return e(),o("div",null,a)}const h=t(r,[["render",c],["__file","introduce.html.vue"]]);export{h as default};
